import 'dart:convert';
import 'package:flutter/services.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class SecretManager {
  static final SecretManager instance = SecretManager._internal();
  SecretManager._internal();

  final FlutterSecureStorage _secureStorage = const FlutterSecureStorage();
  Map<String, String> _secrets = {};
  bool _initialized = false;

  static const String _awsAccessKeyId = 'aws_access_key_id';
  static const String _awsSecretAccessKey = 'aws_secret_access_key';
  static const String _awsRegion = 'aws_region';
  static const String _awsS3Bucket = 'aws_s3_bucket';
  static const String _gcpApiKey = 'gcp_api_key';

  Future<void> initialize() async {
    if (_initialized) return;

    // First, try to load from secure storage (previously saved)
    final storedAccessKey = await _secureStorage.read(key: _awsAccessKeyId);
    if (storedAccessKey != null) {
      _secrets[_awsAccessKeyId] = storedAccessKey;
      _secrets[_awsSecretAccessKey] =
          (await _secureStorage.read(key: _awsSecretAccessKey)) ?? '';
      _secrets[_awsRegion] =
          (await _secureStorage.read(key: _awsRegion)) ?? 'us-east-1';
      _secrets[_awsS3Bucket] =
          (await _secureStorage.read(key: _awsS3Bucket)) ?? '';
      _secrets[_gcpApiKey] =
          (await _secureStorage.read(key: _gcpApiKey)) ?? '';
      _initialized = true;
      return;
    }

    // Load from environment-injected config at build time via --dart-define
    // or from a secrets file that is NOT checked into version control.
    // The secrets file should be in assets/secrets.json (added to .gitignore).
    try {
      final secretsJson =
          await rootBundle.loadString('assets/secrets.json');
      final Map<String, dynamic> parsed = json.decode(secretsJson);
      _secrets[_awsAccessKeyId] = parsed['aws_access_key_id'] ?? '';
      _secrets[_awsSecretAccessKey] = parsed['aws_secret_access_key'] ?? '';
      _secrets[_awsRegion] = parsed['aws_region'] ?? 'us-east-1';
      _secrets[_awsS3Bucket] = parsed['aws_s3_bucket'] ?? '';
      _secrets[_gcpApiKey] = parsed['gcp_api_key'] ?? '';

      // Persist to secure storage so we don't need the asset file again
      for (final entry in _secrets.entries) {
        await _secureStorage.write(key: entry.key, value: entry.value);
      }
    } catch (_) {
      // Fall back to --dart-define values passed at build time:
      // flutter run --dart-define=AWS_ACCESS_KEY_ID=... --dart-define=AWS_SECRET_ACCESS_KEY=... etc.
      _secrets[_awsAccessKeyId] =
          const String.fromEnvironment('AWS_ACCESS_KEY_ID');
      _secrets[_awsSecretAccessKey] =
          const String.fromEnvironment('AWS_SECRET_ACCESS_KEY');
      _secrets[_awsRegion] =
          const String.fromEnvironment('AWS_REGION', defaultValue: 'us-east-1');
      _secrets[_awsS3Bucket] =
          const String.fromEnvironment('AWS_S3_BUCKET');
      _secrets[_gcpApiKey] =
          const String.fromEnvironment('GCP_API_KEY');

      for (final entry in _secrets.entries) {
        if (entry.value.isNotEmpty) {
          await _secureStorage.write(key: entry.key, value: entry.value);
        }
      }
    }

    _initialized = true;
  }

  String get awsAccessKeyId => _secrets[_awsAccessKeyId] ?? '';
  String get awsSecretAccessKey => _secrets[_awsSecretAccessKey] ?? '';
  String get awsRegion => _secrets[_awsRegion] ?? 'us-east-1';
  String get awsS3Bucket => _secrets[_awsS3Bucket] ?? '';
  String get gcpApiKey => _secrets[_gcpApiKey] ?? '';

  bool get isConfigured =>
      awsAccessKeyId.isNotEmpty &&
      awsSecretAccessKey.isNotEmpty &&
      awsS3Bucket.isNotEmpty &&
      gcpApiKey.isNotEmpty;

  /// Allow runtime configuration (e.g., from a settings screen)
  Future<void> setSecrets({
    required String awsAccessKeyId,
    required String awsSecretAccessKey,
    required String awsRegion,
    required String awsS3Bucket,
    required String gcpApiKey,
  }) async {
    _secrets[_awsAccessKeyId] = awsAccessKeyId;
    _secrets[_awsSecretAccessKey] = awsSecretAccessKey;
    _secrets[_awsRegion] = awsRegion;
    _secrets[_awsS3Bucket] = awsS3Bucket;
    _secrets[_gcpApiKey] = gcpApiKey;

    for (final entry in _secrets.entries) {
      await _secureStorage.write(key: entry.key, value: entry.value);
    }
  }
}

// lib/services/s3_service.dart
import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';
import 'package:http/http.dart' as http;
import 'package:path/path.dart' as path;
import 'package:intl/intl.dart';
import 'secret_manager.dart';

class S3Service {
  final SecretManager _secrets = SecretManager.instance;

  String get _accessKeyId => _secrets.awsAccessKeyId;
  String get _secretAccessKey => _secrets.awsSecretAccessKey;
  String get _region => _secrets.awsRegion;
  String get _bucket => _secrets.awsS3Bucket;

  Future<String> uploadImage(File imageFile) async {
    if (!_secrets.isConfigured) {
      throw Exception(
          'AWS credentials not configured. Please set up secrets via '
          'assets/secrets.json, --dart-define, or the settings screen.');
    }

    final fileName =
        'uploads/${DateTime.now().millisecondsSinceEpoch}_${path.basename(imageFile.path)}';
    final bytes = await imageFile.readAsBytes();
    final contentType = _getContentType(imageFile.path);

    final now = DateTime.now().toUtc();
    final dateStamp = DateFormat('yyyyMMdd').format(now);
    final amzDate = DateFormat("yyyyMMdd'T'HHmmss'Z'").format(now);

    final host = '$_bucket.s3.$_region.amazonaws.com';
    final endpoint = 'https://$host/$fileName';

    final payloadHash = sha256.convert(bytes).toString();

    final canonicalHeaders = 'content-type:$contentType\n'
        'host:$host\n'
        'x-amz-content-sha256:$payloadHash\n'
        'x-amz-date:$amzDate\n';

    const signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';

    final canonicalRequest = 'PUT\n'
        '/${Uri.encodeComponent(fileName).replaceAll('%2F', '/')}\n'
        '\n'
        '$canonicalHeaders\n'
        '$signedHeaders\n'
        '$payloadHash';

    final credentialScope = '$dateStamp/$_region/s3/aws4_request';
    final stringToSign = 'AWS4-HMAC-SHA256\n'
        '$amzDate\n'
        '$credentialScope\n'
        '${sha256.convert(utf8.encode(canonicalRequest))}';

    final signingKey = _getSignatureKey(dateStamp);
    final signature = Hmac(sha256, signingKey)
        .convert(utf8.encode(stringToSign))
        .toString();

    final authorization = 'AWS4-HMAC-SHA256 '
        'Credential=$_accessKeyId/$credentialScope, '
        'SignedHeaders=$signedHeaders, '
        'Signature=$signature';

    final response = await http.put(
      Uri.parse(endpoint),
      headers: {
        'Content-Type': contentType,
        'Host': host,
        'x-amz-content-sha256': payloadHash,
        'x-amz-date': amzDate,
        'Authorization': authorization,
      },
      body: bytes,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      return endpoint;
    } else {
      throw Exception(
          'S3 upload failed: ${response.statusCode} ${response.body}');
    }
  }

  List<int> _getSignatureKey(String dateStamp) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$_secretAccessKey'))
        .convert(utf8.encode(dateStamp))
        .bytes;
    final kRegion =
        Hmac(sha256, kDate).convert(utf8.encode(_region)).bytes;
    final kService =
        Hmac(sha256, kRegion).convert(utf8.encode('s3')).bytes;
    final kSigning =
        Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
    return kSigning;
  }

  String _getContentType(String filePath) {
    final ext = path.extension(filePath).toLowerCase();
    switch (ext) {
      case '.jpg':
      case '.jpeg':
        return 'image/jpeg';
      case '.png':
        return 'image/png';
      case '.gif':
        return 'image/gif';
      case '.webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }
}

// lib/services/vision_service.dart
import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;
import 'secret_manager.dart';

class VisionService {
  final SecretManager _secrets = SecretManager.instance;

  String get _apiKey => _secrets.gcpApiKey;

  Future<String> analyzeImage(File imageFile) async {
    if (_apiKey.isEmpty) {
      throw Exception(
          'Google Cloud API key not configured. Please set up secrets.');
    }

    final bytes = await imageFile.readAsBytes();
    final base64Image = base64Encode(bytes);

    final url =
        'https://vision.googleapis.com/v1/images:annotate?key=$_apiKey';

    final requestBody = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'FACE_DETECTION', 'maxResults': 5},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION'},
            {'type': 'IMAGE_PROPERTIES'},
          ],
        }
      ],
    };

    final response = await http.post(
      Uri.parse(url),
      headers: {'Content-Type': 'application/json'},
      body: json.encode(requestBody),
    );

    if (response.statusCode == 200) {
      final result = json.decode(response.body);
      return _formatResults(result);
    } else {
      throw Exception(
          'Vision API error: ${response.statusCode} ${response.body}');
    }
  }

  String _formatResults(Map<String, dynamic> result) {
    final buffer = StringBuffer();
    final responses = result['responses'] as List?;
    if (responses == null || responses.isEmpty) {
      return 'No analysis results.';
    }

    final response = responses[0] as Map<String, dynamic>;

    // Labels
    final labels = response['labelAnnotations'] as List?;
    if (labels != null && labels.isNotEmpty) {
      buffer.writeln('📋 Labels:');
      for (final label in labels) {
        final description = label['description'];
        final score = (label['score'] * 100).toStringAsFixed(1);
        buffer.writeln('  • $description ($score%)');
      }
      buffer.writeln();
    }

    // Objects
    final objects = response['localizedObjectAnnotations'] as List?;
    if (objects != null && objects.isNotEmpty) {
      buffer.writeln('🔍 Objects Detected:');
      for (final obj in objects) {
        final name = obj['name'];
        final score = (obj['score'] * 100).toStringAsFixed(1);
        buffer.writeln('  • $name ($score%)');
      }
      buffer.writeln();
    }

    // Text
    final textAnnotations = response['textAnnotations'] as List?;
    if (textAnnotations != null && textAnnotations.isNotEmpty) {
      buffer.writeln('📝 Text Found:');
      buffer.writeln('  ${textAnnotations[0]['description']}');
      buffer.writeln();
    }

    // Faces
    final faces = response['faceAnnotations'] as List?;
    if (faces != null && faces.isNotEmpty) {
      buffer.writeln('😊 Faces Detected: ${faces.length}');
      for (int i = 0; i < faces.length; i++) {
        final face = faces[i];
        buffer.writeln('  Face ${i + 1}:');
        buffer.writeln('    Joy: ${face['joyLikelihood']}');
        buffer.writeln('    Sorrow: ${face['sorrowLikelihood']}');
        buffer.writeln('    Anger: ${face['angerLikelihood']}');
        buffer.writeln('    Surprise: ${face['surpriseLikelihood']}');
      }
      buffer.writeln();
    }

    // Safe Search
    final safeSearch = response['safeSearchAnnotation'] as Map<String, dynamic>?;
    if (safeSearch != null) {
      buffer.writeln('🛡️ Safe Search:');
      buffer.writeln('  Adult: ${safeSearch['adult']}');
      buffer.writeln('  Violence: ${safeSearch['violence']}');
      buffer.writeln('  Medical: ${safeSearch['medical']}');
      buffer.writeln('  Racy: ${safeSearch['racy']}');
      buffer.writeln();
    }

    // Dominant Colors
    final imageProperties =
        response['imagePropertiesAnnotation'] as Map<String, dynamic>?;
    if (imageProperties != null) {
      final colors = imageProperties['dominantColors']?['colors'] as List?;
      if (colors != null && colors.isNotEmpty) {
        buffer.writeln('🎨 Dominant Colors:');
        for (int i = 0; i < colors.length && i < 5; i++) {
          final color = colors[i]['color'] as Map<String, dynamic>?;
          if (color != null) {
            final r = (color['red'] ?? 0).toInt();
            final g = (color['green'] ?? 0).toInt();
            final b = (color['blue'] ?? 0).toInt();
            final score =
                ((colors[i]['score'] ?? 0) * 100).toStringAsFixed(1);
            buffer.writeln('  • RGB($r, $g, $b) - $score%');
          }
        }
      }
    }

    return buffer.toString().trim();
  }
}

